}

function SalesCell({
  value,
  label,
  dot,
}: {
  value: string;
  label: string;
  dot: string;
}) {
  return (
    <View style={styles.salesCell}>
      <Text style={styles.salesValue}>{value}</Text>
      <View style={styles.salesLabelRow}>
        <View style={[styles.salesDot, { backgroundColor: dot }]} />
        <Text style={styles.metricLabel}>{label}</Text>
      </View>
    </View>
  );
}

function HeaderIcon({ glyph, badge }: { glyph: "service" | "message"; badge?: string }) {
  return (
    <View style={styles.headerIconWrap}>
      <View style={styles.headerIconGlyph}>
        <Text style={styles.headerIconText}>
          {glyph === "service" ? "☎" : "✉"}
        </Text>
      </View>
      {badge ? (
        <View style={styles.headerBadge}>
          <Text style={styles.headerBadgeText}>{badge}</Text>
        </View>
      ) : null}
    </View>
  );
}

/**
 * Placeholder glyph. Swap for your icon set (the app uses expo-image
 * tab icons; a vector icon lib like @expo/vector-icons works here too).
 */
function NavGlyph({ name, color = brand.green }: { name: IconName; color?: string }) {
  const map: Record<IconName, string> = {
    recharge: "↑",
    withdraw: "↓",
    refunds: "⟲",
    train: "⚡",
    promotion: "📣",
    level: "★",
    followers: "♥",
    rating: "★",
    credit: "✓",
  };
  return <Text style={[styles.navGlyph, { color }]}>{map[name]}</Text>;
}

function chunk<T>(arr: T[], size: number): T[][] {
  const out: T[][] = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out;
}

